import 'dotenv/config'
import express from 'express'
import { createServer } from 'http'
import { WebSocketServer, WebSocket } from 'ws'
import { createClient } from '@supabase/supabase-js'
import { tasksRouter } from './routes/tasks.js'

const app = express()
const PORT = process.env.PORT || 3001

app.use((req, res, next) => {
  res.header('Access-Control-Allow-Origin', '*')
  res.header('Access-Control-Allow-Methods', 'GET, POST, DELETE, OPTIONS')
  res.header('Access-Control-Allow-Headers', 'Content-Type, Authorization')
  if (req.method === 'OPTIONS') {
    res.sendStatus(200)
    return
  }
  next()
})

app.use(express.json())

app.use((req, _res, next) => {
  console.log(`${new Date().toISOString()} ${req.method} ${req.path}`)
  next()
})

app.get('/health', (_req, res) => {
  res.json({ ok: true, timestamp: new Date() })
})

app.use('/api', tasksRouter)

app.post('/api/generate-key', async (req, res) => {
  const { userId } = req.body
  if (!userId) return res.status(400).json({ error: 'Missing userId' })

  // Generate a random permanent key
  const key = 'felo_' + [...Array(32)].map(() => Math.random().toString(36)[2]).join('')

  // Upsert — one key per user
  const { error } = await supabase
    .from('api_keys')
    .upsert({ user_id: userId, key }, { onConflict: 'user_id' })

  if (error) return res.status(500).json({ error: 'Failed to generate key' })
  res.json({ key })
})

app.get('/api/get-key/:userId', async (req, res) => {
  const { data } = await supabase
    .from('api_keys')
    .select('key')
    .eq('user_id', req.params.userId)
    .single()
  res.json({ key: data?.key || null })
})

// HTTP server wrapping Express
const server = createServer(app)

// WebSocket server — handles extension connections from all users
const wss = new WebSocketServer({ noServer: true })

server.on('upgrade', (request, socket, head) => {
  const url = new URL(request.url || '', 'http://localhost')
  if (url.pathname === '/extension') {
    wss.handleUpgrade(request, socket, head, (ws) => {
      wss.emit('connection', ws, request)
    })
  } else {
    socket.destroy()
  }
})

// userId -> WebSocket connection
export const extensionConnections = new Map<string, WebSocket>()

// userId -> pending CDP command callbacks
export const pendingCdpCommands = new Map<string, Map<number, { resolve: (v: any) => void, reject: (e: Error) => void }>>()

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY!
)

wss.on('connection', async (ws, req) => {
  const url = new URL(req.url || '', 'http://localhost')
  const token = url.searchParams.get('token')

  if (!token) {
    ws.close(1008, 'Missing token')
    return
  }

  // Verify token with api_keys table
  let userId: string
  try {
    const { data, error } = await supabase
      .from('api_keys')
      .select('user_id')
      .eq('key', token)
      .single()
    if (error || !data) throw new Error('Invalid API key')
    userId = data.user_id
    console.log(`✅ API key valid for user: ${userId}`)
  } catch (err) {
    console.error('Extension auth failed:', String(err))
    ws.close(1008, 'Invalid token')
    return
  }

  // Close any existing connection for this user
  const existing = extensionConnections.get(userId)
  if (existing && existing.readyState === WebSocket.OPEN) {
    existing.close(1000, 'Replaced by new connection')
  }

  extensionConnections.set(userId, ws)
  pendingCdpCommands.set(userId, new Map())
  console.log(`✅ Extension connected: ${userId} (total: ${extensionConnections.size})`)

  // Send welcome message
  ws.send(JSON.stringify({ method: 'connected', params: { userId } }))

  // Keepalive ping every 25 seconds
  const pingInterval = setInterval(() => {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify({ method: 'ping' }))
    }
  }, 25000)

  ws.on('message', (data) => {
    console.log(`RAW MESSAGE from ${userId}:`, String(data).slice(0, 200))
    try {
      const msg = JSON.parse(String(data))

      // Pong from extension keepalive
      if (msg.method === 'pong') return

      // CDP command result coming back from extension
      if (msg.id !== undefined && (msg.result !== undefined || msg.error !== undefined)) {
        const userPending = pendingCdpCommands.get(userId)
        const pending = userPending?.get(msg.id)
        if (pending) {
          userPending!.delete(msg.id)
          if (msg.error) {
            pending.reject(new Error(String(msg.error)))
          } else {
            pending.resolve(msg.result)
          }
        }
        return
      }

      // CDP events from the browser (page navigated, etc)
      if (msg.method === 'forwardCDPEvent') {
        console.log(`CDP event from ${userId}: ${msg.params?.method}`)
      }
    } catch (err) {
      console.error('Extension message error:', err)
    }
  })

  ws.on('close', () => {
    clearInterval(pingInterval)
    if (extensionConnections.get(userId) === ws) {
      extensionConnections.delete(userId)
      pendingCdpCommands.delete(userId)
    }
    console.log(`Extension disconnected: ${userId} (total: ${extensionConnections.size})`)
  })

  ws.on('error', (err) => {
    console.error(`Extension WS error for ${userId}:`, err)
  })
})

// Send a CDP command to a user's extension and wait for the result
let cdpCommandId = 1
export async function sendCdpCommand(
  userId: string,
  method: string,
  params?: object,
  timeoutMs = 15000
): Promise<any> {
  const ws = extensionConnections.get(userId)
  if (!ws || ws.readyState !== WebSocket.OPEN) {
    throw new Error('Extension not connected for this user')
  }

  const id = cdpCommandId++
  const userPending = pendingCdpCommands.get(userId) || new Map()
  pendingCdpCommands.set(userId, userPending)

  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => {
      userPending.delete(id)
      reject(new Error(`CDP command timeout: ${method}`))
    }, timeoutMs)

    userPending.set(id, {
      resolve: (v) => { clearTimeout(timer); resolve(v) },
      reject: (e) => { clearTimeout(timer); reject(e) }
    })

    ws.send(JSON.stringify({
      id,
      method: 'forwardCDPCommand',
      params: { method, params }
    }))
  })
}

export function isExtensionConnected(userId: string): boolean {
  const ws = extensionConnections.get(userId)
  const connected = !!ws && ws.readyState === WebSocket.OPEN
  console.log(`isExtensionConnected(${userId}): ${connected}, map size: ${extensionConnections.size}, all keys: ${[...extensionConnections.keys()].join(',')}`)
  return connected
}

// Extension status endpoint
app.get('/api/extension-status/:userId', (req, res) => {
  res.json({ connected: isExtensionConnected(req.params.userId) })
})

server.listen(PORT, () => {
  console.log(`✅ Felo backend running on port ${PORT}`)
  console.log(`✅ WebSocket ready at /extension`)
})

import OpenAI from 'openai'
import { sendCdpCommand } from '../index.js'

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY })

const SYSTEM_PROMPT = `You are an expert browser automation agent controlling a real Chrome browser.
Rules:
- Always navigate first then snapshot to see the page
- Use refs from snapshot to interact with elements
- The user is already logged into their accounts — do not try to log in
- Complete tasks in minimum steps
- Call done when you have the result`

const tools: OpenAI.Chat.ChatCompletionTool[] = [
  {
    type: 'function',
    function: {
      name: 'navigate',
      description: 'Navigate to a URL in the user real Chrome browser',
      parameters: {
        type: 'object',
        properties: {
          url: { type: 'string' }
        },
        required: ['url']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'snapshot',
      description: 'Get the current page content and accessibility tree',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'click',
      description: 'Click an element by CSS selector or text',
      parameters: {
        type: 'object',
        properties: {
          selector: { type: 'string' }
        },
        required: ['selector']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'type',
      description: 'Type text into an input field',
      parameters: {
        type: 'object',
        properties: {
          selector: { type: 'string' },
          text: { type: 'string' }
        },
        required: ['selector', 'text']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'extract',
      description: 'Extract specific data from the current page',
      parameters: {
        type: 'object',
        properties: {
          instruction: { type: 'string' }
        },
        required: ['instruction']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'scroll',
      description: 'Scroll the page down or up',
      parameters: {
        type: 'object',
        properties: {
          direction: { type: 'string', enum: ['down', 'up'] }
        },
        required: ['direction']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'wait',
      description: 'Wait for page to load',
      parameters: {
        type: 'object',
        properties: {
          ms: { type: 'number' }
        },
        required: ['ms']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'done',
      description: 'Task complete — return the final result',
      parameters: {
        type: 'object',
        properties: {
          result: { type: 'string' }
        },
        required: ['result']
      }
    }
  }
]

async function executeTool(
  name: string,
  args: Record<string, any>,
  userId: string
): Promise<string> {
  switch (name) {
    case 'navigate': {
      await sendCdpCommand(userId, 'Page.navigate', { url: args.url })
      await new Promise(r => setTimeout(r, 1500))
      return `Navigated to ${args.url}`
    }
    case 'snapshot': {
      const result = await sendCdpCommand(userId, 'Runtime.evaluate', {
        expression: `document.body.innerText`,
        returnByValue: true
      })
      const text = result?.result?.value || ''
      const url = await sendCdpCommand(userId, 'Runtime.evaluate', {
        expression: 'window.location.href',
        returnByValue: true
      })
      return `URL: ${url?.result?.value}\n\n${text.slice(0, 4000)}`
    }
    case 'click': {
      await sendCdpCommand(userId, 'Runtime.evaluate', {
        expression: `
          (() => {
            const el = document.querySelector('${args.selector}')
              || [...document.querySelectorAll('*')].find(e => e.textContent.trim() === '${args.selector}')
            if (el) { el.click(); return 'clicked' }
            return 'not found'
          })()
        `,
        returnByValue: true
      })
      await new Promise(r => setTimeout(r, 500))
      return `Clicked ${args.selector}`
    }
    case 'type': {
      await sendCdpCommand(userId, 'Runtime.evaluate', {
        expression: `
          (() => {
            const el = document.querySelector('${args.selector}')
            if (el) {
              el.focus()
              el.value = '${args.text}'
              el.dispatchEvent(new Event('input', { bubbles: true }))
              el.dispatchEvent(new Event('change', { bubbles: true }))
              return 'typed'
            }
            return 'not found'
          })()
        `,
        returnByValue: true
      })
      return `Typed "${args.text}" into ${args.selector}`
    }
    case 'extract': {
      const result = await sendCdpCommand(userId, 'Runtime.evaluate', {
        expression: 'document.body.innerText',
        returnByValue: true
      })
      const text = result?.result?.value || ''
      const response = await openai.chat.completions.create({
        model: 'gpt-4o-mini',
        messages: [
          { role: 'system', content: 'Extract the requested data from the page text. Be specific and structured.' },
          { role: 'user', content: `${args.instruction}\n\nPage text:\n${text.slice(0, 6000)}` }
        ],
        max_tokens: 800
      })
      return response.choices[0].message.content || 'Nothing extracted'
    }
    case 'scroll': {
      const y = args.direction === 'down' ? 600 : -600
      await sendCdpCommand(userId, 'Runtime.evaluate', {
        expression: `window.scrollBy(0, ${y})`,
        returnByValue: false
      })
      return `Scrolled ${args.direction}`
    }
    case 'wait': {
      const ms = Math.min(Number(args.ms) || 1000, 3000)
      await new Promise(r => setTimeout(r, ms))
      return `Waited ${ms}ms`
    }
    case 'done': {
      return `DONE:${args.result}`
    }
    default:
      return `Unknown tool: ${name}`
  }
}

export async function runAgentWithExtension(
  task: string,
  userId: string,
  onStep: (step: string) => Promise<void>
): Promise<string> {
  const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
    { role: 'system', content: SYSTEM_PROMPT },
    { role: 'user', content: task }
  ]

  const emojis: Record<string, string> = {
    navigate: '🌐', snapshot: '👁️', click: '👆',
    type: '⌨️', extract: '🔍', scroll: '⬇️',
    wait: '⏳', done: '✅'
  }

  for (let i = 0; i < 25; i++) {
    const response = await openai.chat.completions.create({
      model: 'gpt-4o-mini',
      messages,
      tools,
      max_tokens: 1000
    })

    const choice = response.choices[0]

    if (choice.finish_reason === 'stop') {
      return choice.message.content || 'Task completed'
    }

    if (choice.finish_reason === 'tool_calls' && choice.message.tool_calls) {
      messages.push(choice.message)

      for (const toolCall of choice.message.tool_calls) {
        // Handle both function and custom tool call types
        if (toolCall.type !== 'function') continue
        const toolName = toolCall.function.name
        const args = JSON.parse(toolCall.function.arguments)

        const stepDesc = toolName === 'navigate'
          ? `🌐 Navigating to ${args.url}`
          : toolName === 'extract'
          ? `🔍 Extracting: ${args.instruction}`
          : toolName === 'done'
          ? `✅ Done`
          : `${emojis[toolName] || '⚙️'} ${toolName}`

        await onStep(stepDesc)

        const result = await executeTool(toolName, args, userId)

        if (result.startsWith('DONE:')) {
          return result.replace('DONE:', '')
        }

        messages.push({
          role: 'tool',
          tool_call_id: toolCall.id,
          content: result
        })
      }
    }
  }

  return 'Max iterations reached'
}

import OpenAI from 'openai'
import type { Page } from 'playwright'

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY })

const SYSTEM_PROMPT = `You are an expert browser automation agent. Complete tasks accurately.

Rules:
- Always navigate to the correct URL first
- Always call snapshot after navigating to see the page
- The snapshot returns numbered refs like [1], [2] next to interactive elements
- Use act with a ref number to click, type, or interact with elements
- Use extract to pull specific data from the current page text
- Call done when you have the result
- Never guess selectors — always use refs from snapshot
- If a page seems empty, call wait then snapshot again
- For dynamic sites, wait 1-2 seconds after navigation before snapshotting`

const tools: OpenAI.Chat.ChatCompletionTool[] = [
  {
    type: 'function',
    function: {
      name: 'navigate',
      description: 'Navigate to a URL',
      parameters: {
        type: 'object',
        properties: {
          url: { type: 'string', description: 'Full URL including https://' }
        },
        required: ['url']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'snapshot',
      description: 'Get the accessibility tree of the current page with numbered refs for interactive elements. Always call this after navigating.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'act',
      description: 'Interact with an element using its ref number from snapshot',
      parameters: {
        type: 'object',
        properties: {
          ref: { type: 'string', description: 'Ref number from snapshot e.g. "1" or "42"' },
          action: {
            type: 'string',
            enum: ['click', 'type', 'press_enter', 'scroll_down', 'scroll_up', 'hover', 'select'],
            description: 'Action to perform'
          },
          text: { type: 'string', description: 'Text to type (only for type action)' },
          value: { type: 'string', description: 'Value to select (only for select action)' }
        },
        required: ['action']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'extract',
      description: 'Extract specific data from the current page',
      parameters: {
        type: 'object',
        properties: {
          instruction: { type: 'string', description: 'What data to extract from the page' }
        },
        required: ['instruction']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'wait',
      description: 'Wait for page content to load',
      parameters: {
        type: 'object',
        properties: {
          ms: { type: 'number', description: 'Milliseconds to wait, max 3000' }
        },
        required: ['ms']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'done',
      description: 'Task is complete — return the final result to the user',
      parameters: {
        type: 'object',
        properties: {
          result: { type: 'string', description: 'The final result to show the user' }
        },
        required: ['result']
      }
    }
  }
]

// Stored refs per page: refNumber -> elementHandle
const pageRefs = new WeakMap<Page, Map<number, string>>()

async function getSnapshot(page: Page): Promise<string> {
  const refs = new Map<number, string>()
  let counter = 0

  // Get accessibility tree - use type assertion for older API
  const snapshot = await (page as any).accessibility?.snapshot?.({ interestingOnly: true }) 
    || await page.evaluate(() => {
      // Fallback: build a simple accessibility tree from DOM
      const getEl = (el: Element): any => {
        const role = el.getAttribute('role') || 
          (el.tagName === 'A' ? 'link' : 
           el.tagName === 'BUTTON' ? 'button' : 
           el.tagName === 'INPUT' ? 'textbox' : 
           el.tagName === 'SELECT' ? 'combobox' : 'generic')
        const name = el.textContent?.trim() || el.getAttribute('name') || el.getAttribute('aria-label') || ''
        const children = Array.from(el.children).map(getEl).filter((c: any) => c.role !== 'generic')
        return { role, name, children }
      }
      return getEl(document.body)
    })

  function processNode(node: any, depth: number): string {
    if (!node) return ''
    const indent = '  '.repeat(depth)
    const role = node.role || ''
    const name = node.name || ''

    let line = ''
    const isInteractive = [
      'link', 'button', 'textbox', 'searchbox', 'combobox',
      'checkbox', 'radio', 'menuitem', 'tab', 'option',
      'spinbutton', 'slider', 'switch'
    ].includes(role.toLowerCase())

    if (isInteractive && name) {
      counter++
      refs.set(counter, name)
      line = `${indent}[${counter}] ${role}: ${name}`
    } else if (name && role !== 'generic' && role !== 'none') {
      line = `${indent}${role}: ${name}`
    }

    const children = (node.children || [])
      .map((child: any) => processNode(child, depth + 1))
      .filter(Boolean)
      .join('\n')

    return [line, children].filter(Boolean).join('\n')
  }

  const tree = processNode(snapshot, 0)
  pageRefs.set(page, refs)

  const url = page.url()
  const title = await page.title()
  return `URL: ${url}\nTitle: ${title}\n\n${tree}`.slice(0, 6000)
}

async function executeTool(
  name: string,
  args: Record<string, any>,
  page: Page
): Promise<string> {
  switch (name) {
    case 'navigate': {
      await page.goto(args.url, { waitUntil: 'domcontentloaded', timeout: 20000 })
      await page.waitForTimeout(500)
      return `Navigated to ${args.url}`
    }

    case 'snapshot': {
      return await getSnapshot(page)
    }

    case 'act': {
      const refs = pageRefs.get(page)
      const refNum = parseInt(args.ref)
      const refName = refs?.get(refNum)
      const action = args.action

      if (action === 'scroll_down') {
        await page.evaluate(() => window.scrollBy(0, 600))
        return 'Scrolled down'
      }
      if (action === 'scroll_up') {
        await page.evaluate(() => window.scrollBy(0, -600))
        return 'Scrolled up'
      }
      if (action === 'press_enter') {
        await page.keyboard.press('Enter')
        return 'Pressed Enter'
      }

      if (!refName) {
        return `Ref ${args.ref} not found in last snapshot. Call snapshot first.`
      }

      try {
        if (action === 'click') {
          await page.getByRole('link', { name: refName, exact: false }).first().click({ timeout: 5000 })
            .catch(() => page.getByRole('button', { name: refName, exact: false }).first().click({ timeout: 5000 }))
            .catch(() => page.getByText(refName, { exact: false }).first().click({ timeout: 5000 }))
          await page.waitForTimeout(500)
          return `Clicked "${refName}"`
        }
        if (action === 'type') {
          await page.getByRole('textbox', { name: refName, exact: false }).first().fill(args.text || '', { timeout: 5000 })
            .catch(() => page.getByRole('searchbox', { name: refName, exact: false }).first().fill(args.text || '', { timeout: 5000 }))
          return `Typed "${args.text}" into "${refName}"`
        }
        if (action === 'hover') {
          await page.getByText(refName, { exact: false }).first().hover({ timeout: 5000 })
          return `Hovered over "${refName}"`
        }
        if (action === 'select') {
          await page.getByRole('combobox', { name: refName, exact: false }).first().selectOption(args.value || '', { timeout: 5000 })
          return `Selected "${args.value}" in "${refName}"`
        }
      } catch (err) {
        return `Action failed on "${refName}": ${String(err)}`
      }
      return `Unknown action: ${action}`
    }

    case 'extract': {
      const text = await page.evaluate(() => document.body.innerText)
      const url = page.url()
      const response = await openai.chat.completions.create({
        model: 'gpt-4o-mini',
        messages: [
          {
            role: 'system',
            content: 'Extract the requested data from the page content. Be specific, structured and complete.'
          },
          {
            role: 'user',
            content: `Page URL: ${url}\nInstruction: ${args.instruction}\n\nPage content:\n${text.slice(0, 8000)}`
          }
        ],
        max_tokens: 1000
      })
      return response.choices[0].message.content || 'Nothing extracted'
    }

    case 'wait': {
      const ms = Math.min(Number(args.ms) || 1000, 3000)
      await page.waitForTimeout(ms)
      return `Waited ${ms}ms`
    }

    case 'done': {
      return `DONE:${args.result}`
    }

    default:
      return `Unknown tool: ${name}`
  }
}

export async function runAgent(
  task: string,
  page: Page,
  onStep: (step: string) => Promise<void>
): Promise<string> {
  const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
    { role: 'system', content: SYSTEM_PROMPT },
    { role: 'user', content: task }
  ]

  const emojis: Record<string, string> = {
    navigate: '🌐',
    snapshot: '👁️',
    act: '👆',
    extract: '🔍',
    wait: '⏳',
    done: '✅'
  }

  for (let i = 0; i < 25; i++) {
    const response = await openai.chat.completions.create({
      model: 'gpt-4o-mini',
      messages,
      tools,
      max_tokens: 1000
    })

    const choice = response.choices[0]

    if (choice.finish_reason === 'stop') {
      return choice.message.content || 'Task completed'
    }

    if (choice.finish_reason === 'tool_calls' && choice.message.tool_calls) {
      messages.push(choice.message)

      for (const toolCall of choice.message.tool_calls) {
        // OpenAI SDK v6+ uses toolCall.name and toolCall.arguments directly
        const tc = toolCall as any
        const toolName = tc.function?.name || tc.name
        const args = JSON.parse(tc.function?.arguments || tc.arguments || '{ }')

        const stepDesc = toolName === 'act'
          ? `${emojis[toolName]} ${args.action} on ref [${args.ref}]${args.text ? `: "${args.text}"` : ''}`
          : toolName === 'navigate'
          ? `${emojis[toolName]} Navigating to ${args.url}`
          : toolName === 'extract'
          ? `${emojis[toolName]} Extracting: ${args.instruction}`
          : toolName === 'done'
          ? `✅ Done`
          : `${emojis[toolName] || '⚙️'} ${toolName}`

        await onStep(stepDesc)

        const result = await executeTool(toolName, args, page)

        if (result.startsWith('DONE:')) {
          return result.replace('DONE:', '')
        }

        messages.push({
          role: 'tool',
          tool_call_id: toolCall.id,
          content: result
        })
      }
    }
  }

  return 'Max iterations reached'
}

import { chromium } from 'playwright'
import type { Browser, Page } from 'playwright'

let browser: Browser | null = null

export async function getBrowser(): Promise<Browser> {
  if (!browser || !browser.isConnected()) {
    browser = await chromium.launch({
      headless: true,
      args: [
        '--no-sandbox',
        '--disable-setuid-sandbox',
        '--disable-dev-shm-usage',
        '--disable-gpu'
      ]
    })
    console.log('🌐 Browser launched')
  }
  return browser
}

export async function newPage(): Promise<Page> {
  const b = await getBrowser()
  const context = await b.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
  })
  return context.newPage()
}

import { createClient } from '@supabase/supabase-js'

export const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY!
)

import { Router } from 'express'
import { supabase } from '../lib/supabase.js'
import { newPage } from '../lib/browser.js'
import { runAgent } from '../lib/agent.js'
import { isExtensionConnected, extensionConnections } from '../index.js'
import { runAgentWithExtension } from '../lib/agent-extension.js'

export const tasksRouter = Router()

async function appendOutput(taskId: string, line: string) {
  const { data } = await supabase
    .from('tasks')
    .select('output')
    .eq('id', taskId)
    .single()
  const current = data?.output || ''
  await supabase
    .from('tasks')
    .update({ output: current + line + '\n', status: 'running' })
    .eq('id', taskId)
}

async function runTaskInBackground(taskId: string, prompt: string, userId: string) {
  console.log(`runTaskInBackground: taskId=${taskId} userId=${userId}`)
  console.log(`Extension connected for ${userId}: ${isExtensionConnected(userId)}`)
  console.log(`All connected users: ${[...extensionConnections.keys()].join(', ')}`)
  const usingExtension = isExtensionConnected(userId)

  if (usingExtension) {
    // Use user's real Chrome via extension
    await appendOutput(taskId, '🔌 Using your real browser via extension\n')
    try {
      const result = await runAgentWithExtension(prompt, userId, async (step) => {
        console.log(`[${taskId}] ${step}`)
        await appendOutput(taskId, step + '\n')
      })
      const { data } = await supabase.from('tasks').select('output').eq('id', taskId).single()
      await supabase.from('tasks').update({
        status: 'done',
        output: (data?.output || '') + `✅ Done: ${result}\n`
      }).eq('id', taskId)
    } catch (err) {
      const { data } = await supabase.from('tasks').select('output').eq('id', taskId).single()
      await supabase.from('tasks').update({
        status: 'error',
        output: (data?.output || '') + `❌ Error: ${String(err)}\n`
      }).eq('id', taskId)
    }
  } else {
    // Fall back to cloud Playwright browser
    await appendOutput(taskId, '☁️ Using cloud browser (connect extension for full access)\n')
    const page = await newPage()
    try {
      const result = await runAgent(prompt, page, async (step) => {
        console.log(`[${taskId}] ${step}`)
        await appendOutput(taskId, step + '\n')
      })
      const { data } = await supabase.from('tasks').select('output').eq('id', taskId).single()
      await supabase.from('tasks').update({
        status: 'done',
        output: (data?.output || '') + `✅ Done: ${result}\n`
      }).eq('id', taskId)
    } catch (err) {
      const { data } = await supabase.from('tasks').select('output').eq('id', taskId).single()
      await supabase.from('tasks').update({
        status: 'error',
        output: (data?.output || '') + `❌ Error: ${String(err)}\n`
      }).eq('id', taskId)
    } finally {
      await page.close()
    }
  }
}

tasksRouter.post('/create-task', async (req, res) => {
  const { prompt, userId } = req.body
  console.log(`Create task: userId=${userId}, extensionConnected=${isExtensionConnected(userId)}`)
  console.log(`All connected extensions: ${[...extensionConnections.keys()].join(', ')}`)
  if (!prompt || !userId) {
    return res.status(400).json({ error: 'Missing prompt or userId' })
  }
  const { data, error } = await supabase
    .from('tasks')
    .insert({ user_id: userId, prompt, output: '', status: 'running' })
    .select()
    .single()
  if (error || !data) {
    console.error('Supabase insert error:', error)
    return res.status(500).json({ error: 'Failed to create task' })
  }
  res.json({ taskId: data.id })
  runTaskInBackground(data.id, prompt, userId)
})

tasksRouter.get('/tasks/:userId', async (req, res) => {
  const { data } = await supabase
    .from('tasks')
    .select('id, prompt, status, output, created_at')
    .eq('user_id', req.params.userId)
    .order('created_at', { ascending: false })
    .limit(50)
  res.json(data || [])
})

tasksRouter.post('/refresh-token', async (req, res) => {
  const { refreshToken } = req.body
  if (!refreshToken) return res.status(400).json({ error: 'Missing refresh token' })
  try {
    const { data, error } = await supabase.auth.refreshSession({ refresh_token: refreshToken })
    if (error || !data.session) throw new Error('Refresh failed')
    res.json({ accessToken: data.session.access_token, refreshToken: data.session.refresh_token })
  } catch (err) {
    res.status(401).json({ error: String(err) })
  }
})
